import React, { Component } from "react";
import Typical from "react-typical";
import Switch from "react-switch";
import { motion } from "framer-motion"; // Import motion

class Header extends Component {
  constructor() {
    super();
    this.state = { checked: false };
    this.onThemeSwitchChange = this.onThemeSwitchChange.bind(this);
  }

  onThemeSwitchChange(checked) {
    this.setState({ checked });
    this.setTheme();
  }

  setTheme() {
    const dataThemeAttribute = "data-theme";
    const body = document.body;
    const newTheme = body.getAttribute(dataThemeAttribute) === "dark" ? "light" : "dark";
    body.setAttribute(dataThemeAttribute, newTheme);
  }

  render() {
    let name = "";
    let titles = [];

    if (this.props.sharedData) {
      name = this.props.sharedData.name;
      titles = this.props.sharedData.titles.map(x => [x.toUpperCase(), 1500]).flat();
    }

    const HeaderTitleTypeAnimation = React.memo(() => {
      return <Typical className="title-styles" steps={titles} loop={50} />
    }, () => true);

    // Animation Variants
    const containerVariants = {
      hidden: { opacity: 0, y: 30 },
      visible: { 
        opacity: 1, 
        y: 0,
        transition: { duration: 0.8, ease: "easeOut", staggerChildren: 0.2 }
      }
    };

    const childVariants = {
      hidden: { opacity: 0, y: 20 },
      visible: { opacity: 1, y: 0 }
    };

    return (
      <header id="home" style={{ height: window.innerHeight - 140, display: 'block' }}>
        <div className="row aligner" style={{ height: '100%' }}>
          <motion.div 
            className="col-md-12"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
          >
            <div>
              {/* Floating Laptop Icon */}
              <motion.div
                animate={{ y: [0, -15, 0] }}
                transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              >
                <span className="iconify header-icon" data-icon="la:laptop-code" data-inline="false"></span>
              </motion.div>

              <br />

              {/* Animated Name */}
              <motion.h1 className="mb-0" variants={childVariants}>
                <Typical steps={[name]} wrapper="p" />
              </motion.h1>

              {/* Animated Titles */}
              <motion.div className="title-container" variants={childVariants}>
                <HeaderTitleTypeAnimation />
              </motion.div>

              {/* Animated Switch */}
              <motion.div 
                variants={childVariants} 
                style={{ 
                  marginTop: '20px', 
                  width: 'fit-content', 
                  margin: '20px auto 0 auto', 
                  borderRadius: '25px',
                  padding: '4px', // Space for the outline
                  display: 'flex',
                  justifyContent: 'center'
                }} 
                whileHover={{ 
                  scale: 1.05,
                  boxShadow: "0px 0px 0px 3px #AE944F" // This creates the visible "outline"
                }} 
                whileTap={{ scale: 0.95 }}
              >
                <Switch
                  checked={this.state.checked}
                  onChange={this.onThemeSwitchChange}
                  offColor="#baaa80"
                  onColor="#353535"
                  className="react-switch mx-auto"
                  width={90}
                  height={40}
                  uncheckedIcon={
                    <span 
                      className="iconify" 
                      data-icon="twemoji:owl" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25 
                      }}
                    ></span>
                  }
                  checkedIcon={
                    <span 
                      className="iconify" 
                      data-icon="noto-v1:sun-with-face" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25 
                      }}
                    ></span>
                  }
                  id="icon-switch"
                />
              </motion.div>
            </div>
          </motion.div>
        </div>
      </header>
    );
  }
}

export default Header;
